public static long solve(long n, long[][] edges, long k) {
    long maxWeight = 0;
    for (long[] edge : edges) {
        if (edge[2] > maxWeight) {
            maxWeight = edge[2];
        }
    }
    long low = 0;
    long high = maxWeight;

    while (low < high) {
        long mid = low + (high - low) / 2;
        int size = (int) n;
        int[] parent = new int[size];
        int[] rank = new int[size];
        for (int i = 0; i < size; i++) {
            parent[i] = i;
            rank[i] = 0;
        }
        int compCount = size;

        for (long[] edge : edges) {
            if (edge[2] > mid) {
                continue;
            }
            int u = (int) edge[0];
            int v = (int) edge[1];
            int rootU = u;
            while (parent[rootU] != rootU) {
                rootU = parent[rootU];
            }
            int rootV = v;
            while (parent[rootV] != rootV) {
                rootV = parent[rootV];
            }
            if (rootU == rootV) {
                continue;
            }
            if (rank[rootU] < rank[rootV]) {
                parent[rootU] = rootV;
            } else if (rank[rootU] > rank[rootV]) {
                parent[rootV] = rootU;
            } else {
                parent[rootV] = rootU;
                rank[rootU]++;
            }
            compCount--;
        }

        if (compCount <= k) {
            high = mid;
        } else {
            low = mid + 1;
        }
    }
    return low;
}
